function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const stars: number[] = [];
    let totalNonAsterisk = n * (n + 1) / 2;
    const totalSubstrings = n * (n + 1) / 2;

    for (let t = 0; t < n; t++) {
        const pos = order[t];
        let left = 0, right = stars.length;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (stars[mid] < pos) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        const i = left;

        let leftNeighbor = -1;
        if (i > 0) leftNeighbor = stars[i - 1];
        let rightNeighbor = n;
        if (i < stars.length) rightNeighbor = stars[i];

        const originalLength = rightNeighbor - leftNeighbor - 1;
        const originalContribution = originalLength * (originalLength + 1) / 2;

        const leftSegLength = pos - leftNeighbor - 1;
        const rightSegLength = rightNeighbor - pos - 1;
        const newContribution = (leftSegLength * (leftSegLength + 1) / 2) + (rightSegLength * (rightSegLength + 1) / 2);
        const delta = newContribution - originalContribution;

        totalNonAsterisk += delta;
        stars.splice(i, 0, pos);

        const validCount = totalSubstrings - totalNonAsterisk;
        if (validCount >= k) {
            return t;
        }
    }

    return -1;
}
